// Config Fetcher Subworkflow - Transform to Config Object
// Version: 1.1 - Fixed field names (Key not Config Key)

const configRecords = $input.first().json.records || [];
const peFirmsRecords = $input.last().json.records || [];

// Build config object from Config table
const config = {};
for (const record of configRecords) {
  const key = record.fields['Key'];
  const value = record.fields['Value'];

  if (key) {
    // Auto-detect type: if it looks like a number, parse it
    const numValue = parseFloat(value);
    if (!isNaN(numValue) && value && value.trim() !== '') {
      config[key] = numValue;
    } else if (value === 'true' || value === 'TRUE') {
      config[key] = true;
    } else if (value === 'false' || value === 'FALSE') {
      config[key] = false;
    } else {
      config[key] = value;
    }
  }
}

// Build PE firms list with aliases
const peFirms = [];
const peAliasMap = {};

for (const record of peFirmsRecords) {
  const firmName = record.fields['Firm Name'];
  const aliases = record.fields['Aliases'] || '';

  if (firmName) {
    peFirms.push(firmName);

    // Add aliases
    if (aliases) {
      const aliasList = aliases.split(',').map(s => s.trim());
      for (const alias of aliasList) {
        if (alias) {
          peAliasMap[alias.toLowerCase()] = firmName;
        }
      }
    }

    // Map firm name to itself (for direct matches)
    peAliasMap[firmName.toLowerCase()] = firmName;
  }
}

// Build PE regex pattern
const allPeTerms = [...peFirms];
for (const alias of Object.keys(peAliasMap)) {
  if (!allPeTerms.some(t => t.toLowerCase() === alias)) {
    allPeTerms.push(alias);
  }
}

// Escape special regex characters and build pattern
const escapedTerms = allPeTerms.map(term => 
  term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')
);
const peRegexPattern = new RegExp('\\b(' + escapedTerms.join('|') + ')\\b', 'i');

return {
  json: {
    config: config,
    peFirms: peFirms,
    peAliasMap: peAliasMap,
    peRegexPattern: peRegexPattern.source,
    _fetchedAt: new Date().toISOString(),
    _configCount: Object.keys(config).length,
    _peFirmCount: peFirms.length
  }
};
